+    ) {
+        let config = ConformalAnomalyConfig {
+            min_calibration: min_cal,
+            calibration_window: 50,
+            alpha: 0.05,
+            centroid_alpha: 0.1,
+        };
+        let mut det = ConformalAnomalyDetector::new(config);
+        let v = vec![1.0_f32, 0.0, 0.0];
