+        // Allow 2x alpha as margin for small sample effects.
+        prop_assert!(
+            fdr <= alpha * 2.0 + 0.02,
+            "fdr={fdr} exceeds 2*alpha={} for alpha={alpha}",
+            alpha * 2.0
+        );
