+        let config = ConformalAnomalyConfig::default();
+        let mut det = ConformalAnomalyDetector::new(config);
+        let v1: Vec<f32> = (0..dim1).map(|i| (i as f32 + 1.0)).collect();
+        for _ in 0..10 {
+            det.observe(&v1);
